import React from "react";
import useSlider from "../hooks/useSlider";
import { HERO_SLIDES } from "../data/siteData";

/**
 * HeroSlider — full-viewport image slider with:
 *   - Ken Burns scale transition on images
 *   - Animated text slides
 *   - RSD watermark
 *   - Light leaks
 *   - Film grain overlay
 *
 * Props:
 *   ready {boolean} — controls entry animations after preloader
 */
const HeroSlider = ({ ready }) => {
  const [current] = useSlider(HERO_SLIDES.length, 6000);

  return (
    <section
      style={{
        position: "relative",
        width: "100%",
        height: "100vh",
        overflow: "hidden",
        background: "#000",
      }}
    >
      {/* ── Slide Images ── */}
      {HERO_SLIDES.map((slide, i) => (
        <img
          key={slide.image}
          src={slide.image}
          alt={slide.title}
          className={`slide-img${i === current ? " active" : ""}`}
        />
      ))}

      {/* ── Dark gradient overlay ── */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "linear-gradient(to bottom, rgba(0,0,0,.68), rgba(0,0,0,.2), rgba(0,0,0,.84))",
          zIndex: 2,
          pointerEvents: "none",
        }}
      />

      {/* ── Light Leak 1 (top-left warm) ── */}
      <div
        className="animate-float1"
        style={{
          position: "absolute",
          width: "700px",
          height: "700px",
          borderRadius: "50%",
          filter: "blur(80px)",
          zIndex: 2,
          top: "-250px",
          left: "-200px",
          background:
            "radial-gradient(circle, rgba(255,180,120,.16), transparent 70%)",
          pointerEvents: "none",
          opacity: ready ? 1 : 0,
          transition: "opacity 3s ease",
          transitionDelay: ready ? "0s" : "0s",
        }}
      />

      {/* ── Light Leak 2 (bottom-right cool) ── */}
      <div
        className="animate-float2"
        style={{
          position: "absolute",
          width: "700px",
          height: "700px",
          borderRadius: "50%",
          filter: "blur(80px)",
          zIndex: 2,
          right: "-250px",
          bottom: "-250px",
          background:
            "radial-gradient(circle, rgba(255,255,255,.08), transparent 70%)",
          pointerEvents: "none",
          opacity: ready ? 1 : 0,
          transition: "opacity 3s ease",
          transitionDelay: ready ? "0.3s" : "0s",
        }}
      />

      {/* ── Film Grain ── */}
      <div className="film-grain" />

      {/* ── RSD Watermark ── */}
      <div
        style={{
          position: "absolute",
          right: "40px",
          top: "50%",
          transform: "translateY(-50%)",
          zIndex: 5,
          fontFamily: "'Plus Jakarta Sans', sans-serif",
          fontWeight: 800,
          fontSize: "clamp(120px, 22vw, 340px)",
          lineHeight: 0.8,
          letterSpacing: "-22px",
          color: "rgba(255,255,255,.06)",
          pointerEvents: "none",
          userSelect: "none",
          opacity: ready ? 1 : 0,
          transition: "opacity 3s ease, transform 3s ease",
          transitionDelay: ready ? "2s" : "0s",
        }}
      >
        RSD
      </div>

      {/* ── Overlay Text Slides ── */}
      <div
        style={{
          position: "absolute",
          left: "clamp(30px, 6vw, 90px)",
          bottom: "clamp(50px, 8vh, 90px)",
          zIndex: 10,
          color: "#fff",
          opacity: ready ? 1 : 0,
          transition: "opacity 2s ease",
          transitionDelay: ready ? "2.2s" : "0s",
        }}
      >
        {HERO_SLIDES.map((slide, i) => (
          <div
            key={slide.title}
            className={`text-slide${i === current ? " active" : ""}`}
          >
            <h2
              style={{
                fontFamily: "'Tenor Sans', serif",
                fontSize: "clamp(32px, 6vw, 88px)",
                fontWeight: 400,
                lineHeight: 1.05,
                textTransform: "uppercase",
                letterSpacing: "2px",
                maxWidth: "950px",
              }}
            >
              {slide.title}
            </h2>
            <p
              style={{
                marginTop: "26px",
                fontSize: "12px",
                letterSpacing: "8px",
                textTransform: "uppercase",
                opacity: 0.85,
              }}
            >
              {slide.subtitle}
            </p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default HeroSlider;
